SELECT COUNT(*)
FROM stock_exchange_listings
WHERE exchange_id = 1001;

SELECT stocks.name, financial_statements.statement_type, financial_statements.revenue
FROM stocks
INNER JOIN financial_statements ON stocks.stock_id = financial_statements.stock_id;

SELECT stocks.name AS StockName, company_profiles.company_name AS CompanyName
FROM stocks
INNER JOIN company_profiles ON stocks.stock_id = company_profiles.stock_id;
